#ifndef EXCHANGER_H_INCLUDED__
#define EXCHANGER_H_INCLUDED__

#include <BC/EventQueue.h>

///////////////////////////////////////////////////////////////////////////////
// Namespace : 
///////////////////////////////////////////////////////////////////////////////

namespace BC
{

///////////////////////////////////////////////////////////////////////////////
// Macros & typedefs
///////////////////////////////////////////////////////////////////////////////

class Exchanger;

///////////////////////////////////////////////////////////////////////////////
// Class : IExchangeHandler
///////////////////////////////////////////////////////////////////////////////

class IExchangeHandler
{
public:
	IExchangeHandler() : m_internal_events_count(0)
		, m_internal_events_state(1){};
	virtual ~IExchangeHandler(){}

	virtual bool	OnBeforeExchangeEvent(BCEventItemS &refEvent)	= 0;
	virtual bool	OnExchangeEvent(BCEventItemS &refEvent)			= 0;
	virtual void	OnExchangeShutdown()							= 0;

	uint64_t			m_internal_events_count;
	uint32_t			m_internal_events_state;
private:
	DECLARE_NO_COPY_CLASS(IExchangeHandler);
};

///////////////////////////////////////////////////////////////////////////////
// End of namespace : BC
///////////////////////////////////////////////////////////////////////////////

} // End of namespace BC

#endif // EXCHANGER_H_INCLUDED__

///////////////////////////////////////////////////////////////////////////////
// End of file : Exchanger.h
